"""
Generador de etiquetas ZPL para impresora Datamax O'Neil E-Class Mark IIIA
Tamaño de etiqueta: 10cm x 6.5cm = 800 x 520 dots a 203 dpi
"""
from dataclasses import dataclass
from typing import List

LOGO_KOLOKA = "^GFA,1800,1800,9,"


@dataclass
class LabelBundle:
    bundle_number: int
    total_bundles: int
    bundle_type: str  # "MDF" o "HERRAJES"
    zpl_content: str


def generate_zpl_label(
    bundle_number: int,
    total_bundles: int,
    bundle_type: str,          # "MDF" o "HERRAJES"
    client_name: str,
    project_name: str,
    instance_name: str,
    qr_uuid: str,
) -> str:
    """
    Genera el código ZPL para UNA etiqueta de bulto.

    Layout (520 x 800 dots, vertical, campos rotados 90 grados con R):
    - Cliente (grande)
    - Proyecto
    - Instancia (hasta 2 lineas, incluye lote y calle)
    - QR grande unico por bulto (uuid-N)
    - TIPO N/Total (muy grande)
    - UUID corto (referencia)
    """
    client_truncated = client_name[:35] if client_name else ""
    project_truncated = project_name[:30] if project_name else ""
    instance_truncated = instance_name[:70] if instance_name else ""
    project_line = f"Proyecto: {project_truncated}"
    bundle_line = f"{bundle_type} {bundle_number}/{total_bundles}"
    qr_content = f"{qr_uuid}-{bundle_number}"

    zpl = f"""^XA
^CI28
^LH0,0
^PW520
^LL800

^FO460,45^A0R,42,42^FD{client_truncated}^FS
^FO415,45^A0R,26,26^FD{project_line}^FS
^FO345,45^A0R,30,30^FB700,2,0,L,0^FD{instance_truncated}^FS

^FO95,45^BQR,2,7^FDQA,{qr_content}^FS

^FO235,400^A0R,48,48^FD{bundle_line}^FS

^FO25,545{LOGO_KOLOKA}^FS

^XZ"""
    return zpl


def generate_all_labels(
    client_name: str,
    project_name: str,
    instance_name: str,
    mdf_bundles: int,
    hardware_bundles: int,
    qr_uuid: str,
) -> List[LabelBundle]:
    """
    Genera todas las etiquetas ZPL para una instancia.
    Orden: primero MDF, luego HERRAJES.
    Retorna una lista de LabelBundle (metadatos + ZPL por bulto).
    """
    total = mdf_bundles + hardware_bundles
    labels: List[LabelBundle] = []
    counter = 1

    for _ in range(mdf_bundles):
        labels.append(LabelBundle(
            bundle_number=counter,
            total_bundles=total,
            bundle_type="MDF",
            zpl_content=generate_zpl_label(
                bundle_number=counter,
                total_bundles=total,
                bundle_type="MDF",
                client_name=client_name,
                project_name=project_name,
                instance_name=instance_name,
                qr_uuid=qr_uuid,
            ),
        ))
        counter += 1

    for _ in range(hardware_bundles):
        labels.append(LabelBundle(
            bundle_number=counter,
            total_bundles=total,
            bundle_type="HERRAJES",
            zpl_content=generate_zpl_label(
                bundle_number=counter,
                total_bundles=total,
                bundle_type="HERRAJES",
                client_name=client_name,
                project_name=project_name,
                instance_name=instance_name,
                qr_uuid=qr_uuid,
            ),
        ))
        counter += 1

    return labels


def concatenate_zpl(labels: List[str]) -> str:
    """Une todas las etiquetas en un solo string ZPL para enviar a la impresora."""
    return "\n".join(labels)
